#include <stdio.h>
#define MOD 998244353

long long modPow2(int k) {
    long long res = 1;
    while (k--) {
        res = (res * 2) % MOD;
    }
    return res;
}

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        int fixed = 0;
        for (int i = 1; i <= N; ++i) {
            int x; scanf("%d", &x);
            if (x == i) ++fixed;
        }
        long long ans = modPow2(fixed);
        if (fixed == N) {
            ans = (ans - 1 + MOD) % MOD;
        }
        printf("%lld\n", ans);
    }
    return 0;
}

