#!/usr/bin/env python3
import sys
MOD = 998244353

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        N = int(next(it))
        fixed = 0
        for i in range(1, N+1):
            x = int(next(it))
            if x == i:
                fixed += 1
        ans = pow(2, fixed, MOD)
        if fixed == N:
            ans = (ans - 1) % MOD
        out.append(str(ans))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

